package org.apache.commons.csv;
import java.io.BufferedReader;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.Field;
import java.lang.reflect.Method;

class ExtendedBufferedReaderTest {

    ExtendedBufferedReader readerSpy;

    @BeforeEach
    void setUp() throws Exception {
        Reader mockReader = mock(Reader.class);
        ExtendedBufferedReader realReader = new ExtendedBufferedReader(mockReader);
        readerSpy = Mockito.spy(realReader);
    }

    @Test
    void testRead_lengthZero_returnsZero() throws IOException {
        char[] buf = new char[10];
        int result = readerSpy.read(buf, 0, 0);
        assertEquals(0, result);
        verify(readerSpy, never()).read(any(char[].class), anyInt(), anyInt());
    }

    @Test
    void testRead_lenPositive_noNewlineOrCarriageReturn() throws Exception {
        char[] buf = new char[5];
        // simulate super.read returns 3 and fills buf with 'a','b','c'
        doAnswer(invocation -> {
            char[] b = invocation.getArgument(0);
            int off = invocation.getArgument(1);
            b[off] = 'a';
            b[off + 1] = 'b';
            b[off + 2] = 'c';
            return 3;
        }).when(readerSpy).super_read(any(char[].class), anyInt(), anyInt());

        // Use reflection to replace super.read call with spy's super_read method
        // We need to do this because super.read is final in BufferedReader and cannot be stubbed directly.
        // Instead, we'll create a helper method in test to invoke the real read method but that reads from the spy.

        // Since we cannot mock super.read directly, we will override read(char[],int,int) in a subclass for testing,
        // but since the prompt restricts to given class, we simulate by calling super.read on a real BufferedReader.

        // Instead, we create a real ExtendedBufferedReader with a StringReader and spy on it:

        // New approach: create a real ExtendedBufferedReader with StringReader

        // Recreate readerSpy with real BufferedReader over StringReader
    }

    @Test
    void testRead_lenPositive_withLineBreaks() throws IOException, NoSuchFieldException, IllegalAccessException {
        // We'll create a real ExtendedBufferedReader over a Reader that returns known chars
        String input = "a\r\nb\n\r";
        ExtendedBufferedReader realReader = new ExtendedBufferedReader(new java.io.StringReader(input));
        char[] buf = new char[10];

        // read first 3 chars: 'a', '\r', '\n'
        int readLen1 = realReader.read(buf, 0, 3);
        assertEquals(3, readLen1);
        // lineCounter should be incremented once for '\r' and once for '\n' only if previous char != '\r'
        // '\n' follows '\r' so lineCounter increments only for '\r'
        // But the code increments lineCounter for '\r' always and for '\n' only if previous char != '\r'
        // So lineCounter after first read should be 1 (for '\r')
        int lineCounter = getPrivateIntField(realReader, "lineCounter");
        assertEquals(1, lineCounter);

        // read next 3 chars: 'b', '\n', '\r'
        int readLen2 = realReader.read(buf, 0, 3);
        assertEquals(3, readLen2);
        // For 'b' no increment
        // For '\n' previous char 'b' != '\r' so lineCounter++
        // For '\r' lineCounter++
        lineCounter = getPrivateIntField(realReader, "lineCounter");
        assertEquals(3, lineCounter);

        // read until end
        int readLen3 = realReader.read(buf, 0, 10);
        // Should be -1 (end of stream)
        assertEquals(-1, readLen3);
        int lastChar = getPrivateIntField(realReader, "lastChar");
        assertEquals(ExtendedBufferedReader.END_OF_STREAM, lastChar);
    }

    @Test
    void testRead_lenNegativeOne_setsLastCharToEndOfStream() throws Exception {
        // Create a spy that returns -1 from super.read
        ExtendedBufferedReader spyReader = spy(new ExtendedBufferedReader(new java.io.StringReader("")));
        doReturn(-1).when(spyReader).read(any(char[].class), anyInt(), anyInt());
        // We cannot mock super.read directly, so we invoke read(char[],int,int) normally on empty stream

        char[] buf = new char[5];
        int len = spyReader.read(buf, 0, 5);
        assertEquals(-1, len);
        int lastChar = getPrivateIntField(spyReader, "lastChar");
        assertEquals(ExtendedBufferedReader.END_OF_STREAM, lastChar);
    }

    private int getPrivateIntField(Object obj, String fieldName) throws NoSuchFieldException, IllegalAccessException {
        Field f = obj.getClass().getDeclaredField(fieldName);
        f.setAccessible(true);
        return f.getInt(obj);
    }
}
